package org.apache.commons.csv;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Field;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.*;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testFormatWithNormalValues() throws IOException {
        String result = csvFormat.format("a", "b", "c");
        assertNotNull(result);
        String expected = "a,b,c";
        assertEquals(expected, result);
    }

    @Test
    public void testFormatWithEmptyValues() {
        String result = csvFormat.format();
        // Empty record results in empty string
        assertEquals("", result);
    }

    @Test
    public void testFormatWithNullValues() {
        String result = csvFormat.format((Object) null, "b", null);
        // nulls will print as empty (default), so commas between values remain
        assertEquals(",b,", result);
    }

    @Test
    public void testFormatIOExceptionIsWrapped() throws Exception {
        // Create a spy of CSVPrinter to throw IOException on printRecord(Object...)
        CSVPrinter spyPrinter = spy(new CSVPrinter(new StringWriter(), CSVFormat.DEFAULT));
        doThrow(new IOException("io exception")).when(spyPrinter).printRecord((Object[]) any());

        // Use reflection to access the private final field 'out' inside CSVPrinter to get the StringWriter
        Field outField = CSVPrinter.class.getDeclaredField("out");
        outField.setAccessible(true);

        // Create a CSVFormat anonymous subclass that overrides format(...) to use spyPrinter
        CSVFormat formatWithMock = new CSVFormat(CSVFormat.DEFAULT.getDelimiter(),
                CSVFormat.DEFAULT.getQuoteCharacter(),
                CSVFormat.DEFAULT.getQuoteMode(),
                CSVFormat.DEFAULT.getCommentMarker(),
                CSVFormat.DEFAULT.getEscapeCharacter(),
                CSVFormat.DEFAULT.getIgnoreSurroundingSpaces(),
                CSVFormat.DEFAULT.getIgnoreEmptyLines(),
                CSVFormat.DEFAULT.getRecordSeparator(),
                CSVFormat.DEFAULT.getNullString(),
                CSVFormat.DEFAULT.getHeaderComments(),
                CSVFormat.DEFAULT.getHeader(),
                CSVFormat.DEFAULT.getSkipHeaderRecord(),
                CSVFormat.DEFAULT.getAllowMissingColumnNames(),
                CSVFormat.DEFAULT.getIgnoreHeaderCase(),
                CSVFormat.DEFAULT.getTrim(),
                CSVFormat.DEFAULT.getTrailingDelimiter(),
                CSVFormat.DEFAULT.getAutoFlush()) {
            @Override
            public String format(final Object... values) {
                try {
                    spyPrinter.printRecord(values);
                    StringWriter sw = (StringWriter) outField.get(spyPrinter);
                    return sw.toString().trim();
                } catch (final IOException e) {
                    throw new IllegalStateException(e);
                }
            }
        };

        IllegalStateException exception = assertThrows(IllegalStateException.class,
                () -> formatWithMock.format("a", "b"));
        assertTrue(exception.getMessage().isEmpty());
        assertTrue(exception.getCause() instanceof IOException);
        assertEquals("io exception", exception.getCause().getMessage());
    }
}
